INSERT INTO `categorias` VALUES (1,'001','Uso indevido e/ou falsificação de documentos do IFPE',NULL,NULL),(2,'002','Uso indevido do uniforme e documento de identificação do IFPE',NULL,NULL),(3,'003','Divulgação, distribuição e afixação de impressos, panfletos ou cartazes, sem autorização da autoridade competente.',NULL,NULL),(4,'004','Realização de festas, rifas, “livros-de-ouro”, venda de comida, objetos, ou outras modalidades de arrecadação de dinheiro e doações, usando o nome do IFPE sem a expressa autorização do Diretor (a) ou ',NULL,NULL),(5,'005','Pratica de jogos de azar com apostas',NULL,NULL),(6,'006','Participação ou incitação de outrem em movimentos que ensejem desordem',NULL,NULL),(7,'007','Facilitação à entrada de pessoas que representem perigo para si e para a comunidade acadêmica',NULL,NULL),(8,'008','Provocação de barulho e participação em algazarras nos locais destinados às aulas e a outras atividades do IFPE que requeiram silêncio e comedimento',NULL,NULL),(9,'009','\"Conservação em seu poder de qualquer equipamento ou instrumento do IFPE, sem a expressa autorização da autoridade competente.',NULL,NULL),(10,'010','Utilização das barragens, rios, lagos e açudes do campus para banho ou pesca sem autorização da autoridade competente.',NULL,NULL),(11,'011','Descumprimento das normas de uso dos alojamentos, refeitório e demais dependências de atividades acadêmicas, administrativas, culturais, esportivas e de lazer estabelecidas pela autoridade competente ',NULL,NULL),(12,'012','Promoção ou permissão da entrada ou permanência de qualquer pessoa não autorizada nos alojamentos da moradia e de semi-moradia.',NULL,NULL),(13,'013','Utilização de qualquer aparelho eletrônico, software ou meios de internet nas atividades acadêmicas sem autorização do docente.',NULL,NULL),(14,'014','Locução de palavra de baixo calão, gesticulação de obscenidades, escrita ou desenhos pornográficos em qualquer dependência ou espaço virtual do IFPE.',NULL,NULL),(15,'015','Utilização dos meios eletrônicos disponibilizados pelo IFPE para ter acesso ou publicar pornografias, dilacerações, ou similares.',NULL,NULL),(16,'016','Praticar atos ou comportamentos obscenos ou que atentem contra a moral e o decoro público',NULL,NULL),(17,'017','Participação ou incitação de movimentos de faltas coletivas às atividades acadêmicas',NULL,NULL),(18,'018','Prática de Bullyng, ou agressão moral contra qualquer pessoa.',NULL,NULL),(19,'019','Consumo, porte, tráfico ou ainda estar sob o efeito de drogas ou substâncias ilícitas ou proibidas.',NULL,NULL),(20,'020','Introdução, porte, uso ou transporte de armas de fogo',NULL,NULL),(21,'021','Introdução, porte, transporte ou uso de substâncias inflamáveis, explosivos ou qualquer objeto que represente perigo para si ou para a comunidade acadêmica',NULL,NULL),(22,'022','Agressão física de qualquer tipo a qualquer pessoa',NULL,NULL),(23,'023','Furto de qualquer proporção ou espécie',NULL,NULL),(24,'024','Dano ou destruição de objetos de outrem',NULL,NULL),(25,'025','Condução de veículo motor em direção perigosa ou sem porte da devida habilitação legal expedida pelo órgão de trânsito',NULL,NULL),(26,'026','Assedio e discriminação de qualquer pessoa por motivo de raça, etnia, classe, credo, gênero, orientação sexual ou outros',NULL,NULL),(27,'027','Tratamento de qualquer pessoa de forma desumana, violenta, aterrorizante, vexatória ou constrangedora',NULL,NULL),(28,'028','Autoria e/ou publicação em imprensa falada, escrita, televisionada, nas redes sociais, ou em quaisquer outros meios de comunicação pública em nome do IFPE, sem autorização expressa do Diretor(a) ou Re',NULL,NULL),(29,'029','Armazenar, consumir ou apresentar-se sob efeito de bebidas alcoólica',NULL,NULL),(38,'999','Outros','2024-04-25 13:09:11','2024-04-25 13:09:11');
