INSERT INTO `medida_disciplinars` VALUES (1,724,5,'2024-03-01','12:44:00',1,'1',14,'A estudante foi chamada até a CAEE porque uma colega de turma informou que ela vem há algum tempo o desrespeitando com palavrões porque sempre quer sentar na mesma cadeira que algumas vezes o colega costuma sentar. A discente foi orientada quanto à postura frente ao colega. Ligamos para sua mãe, a senhora Adriana (87-99913-3052) para informar o ocorrido e pedir apoio para conversar com a discente em casa.','2024-03-01 12:47:18','2024-04-25 12:47:18'),(2,1827,5,'2024-03-13','12:30:00',1,'1',2,'Estudante não estava usando o fardamento e não virá com a farda no resto da semana pois esqueceu em sua cidade o fardamento.','2024-03-13 13:00:55','2024-04-25 13:00:55'),(3,1055,5,'2024-03-13','13:30:00',1,'1',2,'O estudante foi advertido pelo não uso do fardamento.','2024-03-13 13:03:52','2024-04-25 13:03:52'),(4,899,5,'2024-03-13','14:08:00',1,'2',38,'O estudante foi colocado para fora da sala de aula de Algoritmos pelo professor Jair, por estar comendo biscoito em sala de aula e ter falado de boca cheia. O estudante foi advertido verbalmente pela servidora da CAEE, e foi registrado um termo de responsabilidade no Sismed.','2024-03-13 13:11:26','2024-04-25 13:11:26'),(5,1202,5,'2024-03-25','13:14:00',1,'2',2,'A estudante veio para a escola sem o uso do fardamento, o que de acordo com a nossa organização acadêmica, não pode acontecer, uma vez que é obrigatório o uso do fardamento.','2024-03-25 13:14:00','2024-04-25 13:14:00'),(6,1617,5,'2024-03-27','13:00:00',1,'1',2,'A estudante foi advertida verbalmente pelo não uso do fardamento.','2024-03-27 13:16:04','2024-04-25 13:16:04'),(7,1901,5,'2024-04-12','12:26:00',1,'1',2,'A estudante foi advertida verbalmente pelo não uso do fardamento.','2024-04-12 13:17:33','2024-04-25 13:17:33'),(8,808,5,'2024-04-15','07:30:00',1,'1',2,'A estudante foi advertida verbalmente pelo não uso do fardamento.','2024-04-15 13:18:54','2024-04-25 13:18:54');
